ius: 20px;\n    font-size: 11px;\n    color: #D4AF37;\n    font-weight: 600;\n    letter-spacing: 0.04em;\n  }\n\n  .countdown {\n    display: flex;\n    gap: 12px;\n    justify-content: center;\n  }\n\n  .countdown-unit {\n    flex: 1;\n    background: rgba(0,0,0,0.3);\n    border: 1px solid rgba(212,175,55,0.1);\n    border-radius: 12px;\n    padding: 12px 8px;\n    text-align: center;\n  }\n\n  .countdown-unit .number {\n    font-size: 26px;\n    font-weight: 800;\n    color: #D4AF37;\n    line-height: 1;\n    letter-spacing: -0.02em;\n    margin-bottom: 4px;\n  }\n\n  .countdown-unit .label {\n    font-size: 9px;\n    color: #6B6660;\n    text-transform: uppercase;\n    letter-spacing: 0.12em;\n    font-weight: 600;\n  }\n\n  .hero-cta {\n    margin-top: 20px;\n    width: 100%;\n    padding: 14px;\n    background: linear-gradient(135deg, #C9A84C, #8B6914);\n    border: none;\n    border-radius: 12px;\n    color: #0D0D10;\n    font-size: 14px;\n    font-weight: 700;\n    letter-spacing: 0.04em;\n    cursor: pointer;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    gap: 8px;\n  }\n\n  /* Upcoming section */\n  .section-header {\n    display: flex;\n    justify-content: space-between;\n    align-items: center;\n    padding: 28px 24px 12px;\n  }\n\n  .section-title {\n    font-size: 11px;\n    letter-spacing: 0.14em;\n    text-transform: uppercase;\n    color: #6B6660;\n    font-weight: 600;\n  }\n\n  .section-action {\n    font-size: 12px;\n    color: #D4AF37;\n    font-weight: 600;\n    letter-spacing: 0.04em;\n  }\n\n  /* Birthday cards */\n  .cards-list {\n    padding: 0 24px;\n    display: flex;\n    flex-direction: column;\n    gap: 12px;\n  }\n\n  .bday-card {\n    background: #111114;\n    border: 1px solid rgba(255,255,255,0.06);\n    border-radius: 16px;\n    padding: 16px;\n    display: flex;\n    align-items: center;\n    gap: 14px;\n    position: relative;\n    overflow: hidden;\n  }\n\n  .bday-card.soon {\n    border-color: rgba(212,175,55,0.2);\n    background: linear-gradient(135deg, #131108, #111114);\n  }\n\n  .bday-card::before {\n    content: '''';\n    position: absolute;\n    left: 0; top: 0; bottom: 0;\n    width: 3px;\n    border-radius: 3px 0 0 3px;\n    background: transparent;\n  }\n\n  .bday-card.soon::before {\n    background: linear-gradient(180deg, #D4AF37, #8B6914);\n  }\n\n  .bday-card.medium::before {\n    background: rgba(255,255,255,0.1);\n  }\n\n  .card-avatar {\n    width: 44px;\n    height: 44px;\n    border-radius: 50%;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    font-size: 20px;\n    flex-shrink: 0;\n    background: #1A1A1E;\n    border: 1.5px solid rgba(255,255,255,0.06);\n  }\n\n  .bday-card.soon .card-avatar {\n    border-color: rgba(212,175,55,0.2);\n    background: #1A1710;\n  }\n\n  .card-info {\n    flex: 1;\n    min-width: 0;\n  }\n\n  .card-name {\n    font-size: 15px;\n    font-weight: 600;\n    color: #F0EDE8;\n    letter-spacing: -0.01em;\n    margin-bottom: 3px;\n    white-space: nowrap;\n    overflow: hidden;\n    text-overflow: ellipsis;\n  }\n\n  .card-meta {\n    font-size: 12px;\n    color: #6B6660;\n    font-weight: 400;\n  }\n\n  .card-meta .relation-tag {\n    color: #8A8680;\n  }\n\n  .card-right {\n    text-align: right;\n    flex-shrink: 0;\n  }\n\n  .days-badge {\n    display: inline-block;\n    padding: 4px 10px;\n    border-radius: 20px;\n    font-size: 12px;\n    font-weight: 700;\n    letter-spacing: 0.02em;\n    margin-bottom: 4px;\n  }\n\n  .days-badge.urgent {\n    background: rgba(212,175,55,0.15);\n    color: #D4AF37;\n    border: 1px solid rgba(212,175,55,0.25);\n  }\n\n  .days-badge.soon {\n    background: rgba(255,255,255,0.05);\n    color: #8A8680;\n    border: 1px solid rgba(255,255,255,0.08);\n  }\n\n  .card-date {\n    font-size: 11px;\n    color: #4A4640;\n    font-weight: 500;\n  }\n\n  /* Bottom nav */\n  .bottom-nav {\n    position: sticky;\n    bottom: 0;\n    margin-top: 32px;\n    padding: 16px 24px 34px;\n    background: linear-gradient(180deg, transparent 0%, #0D0D10 30%);\n    display: flex;\n    justify-content: space-around;\n    align-items: center;\n  }\n\n  .nav-item {\n    display: flex;\n    flex-direction: column;\n    align-items: center;\n    gap: 5px;\n    cursor: pointer;\n  }\n\n  .nav-icon {\n    font-size: 22px;\n    opacity: 0.4;\n  }\n\n  .nav-item.active .nav-icon { opacity: 1; }\n\n  .nav-label {\n    font-size: 10px;\n    color: #4A4640;\n    letter-spacing: 0.06em;\n    text-transform: uppercase;\n    font-weight: 600;\n  }\n\n  .nav-item.active .nav-label {\n    color: #D4AF37;\n  }\n\n  .add-btn {\n    width: 52px;\n    height: 52px;\n    border-radius: 50%;\n    background: linear-gradient(135deg, #C9A84C, #8B6914);\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    font-size: 24px;\n    color: #0D0D10;\n    font-weight: 300;\n    box-shadow: 0 4px 20px rgba(212,175,55,0.3);\n    margin-top: -8px;\n  }\n\n  /* Live countdown ticker */\n  @keyframes pulse-gold {\n    0%, 100% { opacity: 1; }\n    50% { opacity: 0.6; }\n  }\n\n  .live-dot {\n    display: inline-block;\n    width: 6px;\n    height: 6px;\n    border-radius: 50%;\n    background: #D4AF37;\n    animation: pulse-gold 2s ease-in-out infinite;\n    margin-right: 6px;\n    vertical-align: middle;\n  }\n</style>\n</head>\n<body>\n<div class=\"phone\">\n\n  <!-- Status Bar -->\n  <div class=\"status-bar\">\n    <span class=\"time\">9:41</span>\n    <div class=\"status-icons\">\n      <span>●●●</span>\n      <span>WiFi</span>\n      <span>🔋</span>\n    </div>\n  </div>\n\n  <!-- Header -->\n  <div class=\"header\">\n    <div class=\"header-top\">\n      <div class=\"greeting\">Good morning</div>\n      <div class=\"avatar\">J</div>\n    </div>\n    <div class=\"header-title\">Your <span>Celebrations</span></div>\n  </div>\n\n  <!-- Next Up Hero -->\n  <div class=\"next-up-label\">\n    <span class=\"live-dot\"></span> Next up\n  </div>\n\n  <div class=\"hero-card\">\n    <div class=\"hero-person\">\n      <div class=\"hero-avatar\">👩</div>\n      <div class=\"hero-info\">\n        <div class=\"name\">Mom</div>\n        <div class=\"relation\">Family</div>\n        <div class=\"age-tag\">Turning 62</div>\n      </div>\n    </div>\n\n    <div class=\"countdown\">\n      <div class=\"countdown-unit\">\n        <div class=\"number\" id=\"days\">08</div>\n        <div class=\"label\">Days</div>\n      </div>\n      <div class=\"countdown-unit\">\n        <div class=\"number\" id=\"hours\">14</div>\n        <div class=\"label\">Hours</div>\n      </div>\n      <div class=\"countdown-unit\">\n        <div class=\"number\" id=\"mins\">32</div>\n        <div class=\"label\">Mins</div>\n      </div>\n      <div class=\"countdown-unit\">\n        <div class=\"number\" id=\"secs\">07</div>\n        <div class=\"label\">Secs</div>\n      </div>\n    </div>\n\n    <button class=\"hero-cta\">🎁 Plan Celebration</button>\n  </div>\n\n  <!-- Upcoming -->\n  <div class=\"section-header\">\n    <span class=\"section-title\">Coming up</span>\n    <span class=\"section-action\">See all</span>\n  </div>\n\n  <div class=\"cards-list\">\n\n    <div class=\"bday-card soon\">\n      <div class=\"card-avatar\">👦</div>\n      <div class=\"card-info\">\n        <div class=\"card-name\">Marcus</div>\n        <div class=\"card-meta\"><span class=\"relation-tag\">Best Friend</span> · Turning 29</div>\n      </div>\n      <div class=\"card-right\">\n        <div class=\"days-badge urgent\">14 days</div>\n        <div class=\"card-date\">Jul 23</div>\n      </div>\n    </div>\n\n    <div class=\"bday-card soon\">\n      <div class=\"card-avatar\">👧</div>\n      <div class=\"card-info\">\n        <div class=\"card-name\">Sophia</div>\n        <div class=\"card-meta\"><span class=\"relation-tag\">Sister</span> · Turning 27</div>\n      </div>\n      <div class=\"card-right\">\n        <div class=\"days-badge urgent\">21 days</div>\n        <div class=\"card-date\">Jul 30</div>\n      </div>\n    </div>\n\n    <div class=\"bday-card medium\">\n      <div class=\"card-avatar\">🧑</div>\n      <div class=\"card-info\">\n        <div class=\"card-name\">David Kim</div>\n        <div class=\"card-meta\"><span class=\"relation-tag\">Colleague</span> · Turning 34</div>\n      </div>\n      <div class=\"card-right\">\n        <div class=\"days-badge soon\">38 days</div>\n        <div class=\"card-date\">Aug 16</div>\n      </div>\n    </div>\n\n    <div class=\"bday-card medium\">\n      <div class=\"card-avatar\">👴</div>\n      <div class=\"card-info\">\n        <div class=\"card-name\">Grandpa Joe</div>\n        <div class=\"card-meta\"><span class=\"relation-tag\">Family</span> · Turning 78</div>\n      </div>\n      <div class=\"card-right\">\n        <div class=\"days-badge soon\">52 days</div>\n        <div class=\"card-date\">Aug 30</div>\n      </div>\n    </div>\n\n  </div>\n\n  <!-- Bottom Nav -->\n  <div class=\"bottom-nav\">\n    <div class=\"nav-item active\">\n      <div class=\"nav-icon\">🏠</div>\n      <div class=\"nav-label\">Home</div>\n    </div>\n    <div class=\"nav-item\">\n      <div class=\"nav-icon\">📅</div>\n      <div class=\"nav-label\">Calendar</div>\n    </div>\n    <div class=\"add-btn\">+</div>\n    <div class=\"nav-item\">\n      <div class=\"nav-icon\">🎁</div>\n      <div class=\"nav-label\">Gifts</div>\n    </div>\n    <div class=\"nav-item\">\n      <div class=\"nav-icon\">👤</div>\n      <div class=\"nav-label\">Profile</div>\n    </div>\n  </div>\n\n</div>\n\n<script>\n  function updateCountdown() {\n    const now = new Date();\n    // Set Mom''s birthday to 8 days from now for demo\n    const target = new Date(now.getTime() + (8 * 24 * 60 * 60 * 1000));\n    target.setHours(0, 0, 0, 0);\n    const diff = target - now;\n    if (diff <= 0) return;\n    const days = Math.floor(diff / (1000 * 60 * 60 * 24));\n    const hours = Math.floor((diff % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));\n    const mins = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));\n    const secs = Math.floor((diff % (1000 * 60)) / 1000);\n    document.getElementById(''days'').textContent = String(days).padStart(2, ''0'');\n    document.getElementById(''hours'').textContent = String(hours).padStart(2, ''0'');\n    document.getElementById(''mins'').textContent = String(mins).padStart(2, ''0'');\n    document.getElementById(''secs'').textContent = String(secs).padStart(2, ''0'');\n  }\n  updateCountdown();\n  setInterval(updateCountdown, 1000);\n</script>\n\n</body>\n</html>"}

I''ve sent this to your sandbox — tap PREVIEW to see it live.

The countdown timer is live and ticking in real time. A few things worth noting about the design decisions:

- **Hero card** for the most urgent birthday — draws the eye immediately
- **Gold accent line** on the left edge of cards fades as urgency decreases — subtle but effective hierarchy
- **"Plan Celebration" CTA** on the hero card — gives the app a clear action, not just a tracker
- Bottom nav includes a **Gifts tab** — worth thinking about whether gift tracking is in scope for v1

