\n    font-size: 14px;\n    font-weight: 700;\n    color: #0D0D0F;\n    border: 1.5px solid rgba(212,175,55,0.3);\n  }\n\n  .title {\n    font-size: 28px;\n    font-weight: 700;\n    color: #F5F0E8;\n    letter-spacing: -0.02em;\n    line-height: 1.1;\n  }\n\n  .title span {\n    background: linear-gradient(135deg, #D4AF37 0%, #F5D878 50%, #B8942A 100%);\n    -webkit-background-clip: text;\n    -webkit-text-fill-color: transparent;\n    background-clip: text;\n  }\n\n  /* Stats row */\n  .stats-row {\n    display: flex;\n    gap: 12px;\n    padding: 0 24px 24px;\n    position: relative;\n    z-index: 10;\n  }\n\n  .stat-chip {\n    flex: 1;\n    background: rgba(212,175,55,0.06);\n    border: 1px solid rgba(212,175,55,0.12);\n    border-radius: 12px;\n    padding: 12px 14px;\n    text-align: center;\n  }\n\n  .stat-number {\n    font-size: 22px;\n    font-weight: 700;\n    color: #D4AF37;\n    line-height: 1;\n    margin-bottom: 4px;\n  }\n\n  .stat-label {\n    font-size: 10px;\n    color: #5A4F3A;\n    font-weight: 600;\n    letter-spacing: 0.08em;\n    text-transform: uppercase;\n  }\n\n  /* Section header */\n  .section-header {\n    display: flex;\n    justify-content: space-between;\n    align-items: center;\n    padding: 0 24px 14px;\n    position: relative;\n    z-index: 10;\n  }\n\n  .section-title {\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: 0.12em;\n    text-transform: uppercase;\n    color: #5A4F3A;\n  }\n\n  .see-all {\n    font-size: 12px;\n    color: #D4AF37;\n    font-weight: 600;\n    opacity: 0.8;\n  }\n\n  /* Cards */\n  .cards {\n    padding: 0 24px;\n    display: flex;\n    flex-direction: column;\n    gap: 14px;\n    position: relative;\n    z-index: 10;\n  }\n\n  .birthday-card {\n    background: linear-gradient(145deg, #161618 0%, #111113 100%);\n    border: 1px solid rgba(212,175,55,0.12);\n    border-radius: 20px;\n    padding: 20px;\n    position: relative;\n    overflow: hidden;\n    transition: transform 0.2s ease;\n  }\n\n  .birthday-card.urgent {\n    border-color: rgba(212,175,55,0.35);\n    background: linear-gradient(145deg, #1A1710 0%, #131108 100%);\n  }\n\n  .birthday-card::before {\n    content: '''';\n    position: absolute;\n    top: 0;\n    right: 0;\n    width: 120px;\n    height: 120px;\n    background: radial-gradient(circle at top right, rgba(212,175,55,0.06) 0%, transparent 65%);\n    pointer-events: none;\n  }\n\n  .card-top {\n    display: flex;\n    align-items: center;\n    gap: 14px;\n    margin-bottom: 16px;\n  }\n\n  .person-avatar {\n    width: 48px;\n    height: 48px;\n    border-radius: 50%;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    font-size: 20px;\n    flex-shrink: 0;\n    border: 1.5px solid rgba(212,175,55,0.2);\n    position: relative;\n  }\n\n  .person-avatar.urgent-ring {\n    border-color: rgba(212,175,55,0.6);\n    box-shadow: 0 0 0 3px rgba(212,175,55,0.1);\n  }\n\n  .person-info {\n    flex: 1;\n  }\n\n  .person-name {\n    font-size: 17px;\n    font-weight: 700;\n    color: #F5F0E8;\n    letter-spacing: -0.01em;\n    margin-bottom: 3px;\n  }\n\n  .person-relation {\n    font-size: 11px;\n    color: #5A4F3A;\n    font-weight: 600;\n    letter-spacing: 0.06em;\n    text-transform: uppercase;\n  }\n\n  .days-badge {\n    text-align: right;\n    flex-shrink: 0;\n  }\n\n  .days-number {\n    font-size: 28px;\n    font-weight: 800;\n    line-height: 1;\n    background: linear-gradient(135deg, #D4AF37, #F5D878);\n    -webkit-background-clip: text;\n    -webkit-text-fill-color: transparent;\n    background-clip: text;\n  }\n\n  .days-label {\n    font-size: 10px;\n    color: #5A4F3A;\n    font-weight: 600;\n    letter-spacing: 0.08em;\n    text-transform: uppercase;\n  }\n\n  .days-badge.today .days-number {\n    background: linear-gradient(135deg, #FFD700, #FFF0A0);\n    -webkit-background-clip: text;\n    -webkit-text-fill-color: transparent;\n    background-clip: text;\n    animation: pulse 2s ease-in-out infinite;\n  }\n\n  @keyframes pulse {\n    0%, 100% { opacity: 1; }\n    50% { opacity: 0.6; }\n  }\n\n  /* Countdown bar */\n  .countdown-bar {\n    display: flex;\n    gap: 8px;\n    margin-bottom: 14px;\n  }\n\n  .countdown-unit {\n    flex: 1;\n    background: rgba(255,255,255,0.03);\n    border: 1px solid rgba(212,175,55,0.08);\n    border-radius: 10px;\n    padding: 8px 4px;\n    text-align: center;\n  }\n\n  .countdown-value {\n    font-size: 16px;\n    font-weight: 700;\n    color: #D4AF37;\n    line-height: 1;\n    margin-bottom: 3px;\n    font-variant-numeric: tabular-nums;\n  }\n\n  .countdown-unit-label {\n    font-size: 8px;\n    color: #3D3428;\n    font-weight: 700;\n    letter-spacing: 0.1em;\n    text-transform: uppercase;\n  }\n\n  /* Progress strip */\n  .progress-strip {\n    height: 2px;\n    background: rgba(212,175,55,0.08);\n    border-radius: 2px;\n    overflow: hidden;\n    margin-bottom: 14px;\n  }\n\n  .progress-fill {\n    height: 100%;\n    background: linear-gradient(90deg, #8B6914, #D4AF37, #F5D878);\n    border-radius: 2px;\n    transition: width 0.3s ease;\n  }\n\n  /* Card footer */\n  .card-footer {\n    display: flex;\n    gap: 8px;\n  }\n\n  .action-btn {\n    flex: 1;\n    padding: 9px 12px;\n    border-radius: 10px;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: 0.05em;\n    text-align: center;\n    cursor: pointer;\n    border: none;\n  }\n\n  .action-btn.primary {\n    background: linear-gradient(135deg, #D4AF37, #B8942A);\n    color: #0D0D0F;\n  }\n\n  .action-btn.secondary {\n    background: rgba(212,175,55,0.08);\n    color: #8B7355;\n    border: 1px solid rgba(212,175,55,0.12);\n  }\n\n  /* Bottom nav */\n  .bottom-nav {\n    position: sticky;\n    bottom: 0;\n    left: 0;\n    right: 0;\n    background: rgba(13,13,15,0.92);\n    backdrop-filter: blur(20px);\n    -webkit-backdrop-filter: blur(20px);\n    border-top: 1px solid rgba(212,175,55,0.08);\n    display: flex;\n    justify-content: space-around;\n    align-items: center;\n    padding: 12px 0 28px;\n    margin-top: 24px;\n    z-index: 100;\n  }\n\n  .nav-item {\n    display: flex;\n    flex-direction: column;\n    align-items: center;\n    gap: 4px;\n    opacity: 0.4;\n    cursor: pointer;\n  }\n\n  .nav-item.active {\n    opacity: 1;\n  }\n\n  .nav-icon {\n    font-size: 22px;\n    line-height: 1;\n  }\n\n  .nav-label {\n    font-size: 9px;\n    font-weight: 700;\n    letter-spacing: 0.08em;\n    text-transform: uppercase;\n    color: #5A4F3A;\n  }\n\n  .nav-item.active .nav-label {\n    color: #D4AF37;\n  }\n\n  /* Today banner */\n  .today-banner {\n    margin: 0 24px 14px;\n    background: linear-gradient(135deg, rgba(212,175,55,0.15) 0%, rgba(212,175,55,0.05) 100%);\n    border: 1px solid rgba(212,175,55,0.3);\n    border-radius: 14px;\n    padding: 12px 16px;\n    display: flex;\n    align-items: center;\n    gap: 10px;\n    position: relative;\n    z-index: 10;\n  }\n\n  .today-icon {\n    font-size: 22px;\n  }\n\n  .today-text {\n    flex: 1;\n  }\n\n  .today-name {\n    font-size: 13px;\n    font-weight: 700;\n    color: #F5D878;\n    margin-bottom: 1px;\n  }\n\n  .today-sub {\n    font-size: 11px;\n    color: #8B7355;\n  }\n\n  .today-cta {\n    font-size: 11px;\n    font-weight: 700;\n    color: #D4AF37;\n    background: rgba(212,175,55,0.12);\n    padding: 6px 12px;\n    border-radius: 8px;\n    white-space: nowrap;\n  }\n</style>\n</head>\n<body>\n<div class=\"phone\">\n\n  <!-- Status Bar -->\n  <div class=\"status-bar\">\n    <span>9:41</span>\n    <div class=\"status-right\">\n      <span>●●●</span>\n      <span>WiFi</span>\n      <span>🔋</span>\n    </div>\n  </div>\n\n  <!-- Header -->\n  <div class=\"header\">\n    <div class=\"header-top\">\n      <span class=\"greeting\">Good morning, Jochanae</span>\n      <div class=\"avatar\">J</div>\n    </div>\n    <div class=\"title\">Upcoming <span>Birthdays</span></div>\n  </div>\n\n  <!-- Stats -->\n  <div class=\"stats-row\">\n    <div class=\"stat-chip\">\n      <div class=\"stat-number\">12</div>\n      <div class=\"stat-label\">This Month</div>\n    </div>\n    <div class=\"stat-chip\">\n      <div class=\"stat-number\">3</div>\n      <div class=\"stat-label\">This Week</div>\n    </div>\n    <div class=\"stat-chip\">\n      <div class=\"stat-number\">1</div>\n      <div class=\"stat-label\">Today</div>\n    </div>\n  </div>\n\n  <!-- Today Banner -->\n  <div class=\"today-banner\">\n    <div class=\"today-icon\">🎂</div>\n    <div class=\"today-text\">\n      <div class=\"today-name\">Marcus Williams turns 32 today</div>\n      <div class=\"today-sub\">Don''t forget to wish him well</div>\n    </div>\n    <div class=\"today-cta\">Send 🎉</div>\n  </div>\n\n  <!-- Section Header -->\n  <div class=\"section-header\">\n    <span class=\"section-title\">Coming Up</span>\n    <span class=\"see-all\">See all</span>\n  </div>\n\n  <!-- Cards -->\n  <div class=\"cards\">\n\n    <!-- Card 1 — urgent -->\n    <div class=\"birthday-card urgent\">\n      <div class=\"card-top\">\n        <div class=\"person-avatar urgent-ring\">👩🏾</div>\n        <div class=\"person-info\">\n          <div class=\"person-name\">Amara Johnson</div>\n          <div class=\"person-relation\">Sister · Turns 28</div>\n        </div>\n        <div class=\"days-badge\">\n          <div class=\"days-number\">3</div>\n          <div class=\"days-label\">Days left</div>\n        </div>\n      </div>\n      <div class=\"countdown-bar\">\n        <div class=\"countdown-unit\">\n          <div class=\"countdown-value\">0</div>\n          <div class=\"countdown-unit-label\">Wks</div>\n        </div>\n        <div class=\"countdown-unit\">\n          <div class=\"countdown-value\">3</div>\n          <div class=\"countdown-unit-label\">Days</div>\n        </div>\n        <div class=\"countdown-unit\">\n          <div class=\"countdown-value\">14</div>\n          <div class=\"countdown-unit-label\">Hrs</div>\n        </div>\n        <div class=