ARTIFACT: {"type":"html","title":"Birthday Celebration Tracker — Home Screen","content":"<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"UTF-8\" />\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n  <title>Birthday Tracker</title>\n  <link href=\"https://fonts.googleapis.com/css2?family=Cormorant+Garamond:wght@300;400;500;600&family=Inter:wght@300;400;500&display=swap\" rel=\"stylesheet\" />\n  <style>\n    * { margin: 0; padding: 0; box-sizing: border-box; }\n\n    body {\n      background: #0d0d0f;\n      color: #f5f0e8;\n      font-family: ''Inter'', sans-serif;\n      min-height: 100vh;\n      max-width: 430px;\n      margin: 0 auto;\n      overflow-x: hidden;\n    }\n\n    /* ── STATUS BAR ── */\n    .status-bar {\n      display: flex;\n      justify-content: space-between;\n      align-items: center;\n      padding: 12px 24px 4px;\n      font-size: 12px;\n      font-weight: 500;\n      color: #f5f0e8;\n      opacity: 0.7;\n    }\n\n    /* ── HEADER ── */\n    .header {\n      padding: 20px 24px 8px;\n      display: flex;\n      justify-content: space-between;\n      align-items: flex-start;\n    }\n\n    .header-left h1 {\n      font-family: ''Cormorant Garamond'', serif;\n      font-size: 32px;\n      font-weight: 300;\n      letter-spacing: 0.02em;\n      line-height: 1.1;\n      color: #f5f0e8;\n    }\n\n    .header-left p {\n      font-size: 13px;\n      color: #9a8f7e;\n      margin-top: 4px;\n      font-weight: 300;\n    }\n\n    .avatar {\n      width: 40px;\n      height: 40px;\n      border-radius: 50%;\n      background: linear-gradient(135deg, #c9a84c, #e8d5a3);\n      display: flex;\n      align-items: center;\n      justify-content: center;\n      font-size: 15px;\n      font-weight: 500;\n      color: #0d0d0f;\n      flex-shrink: 0;\n    }\n\n    /* ── NEXT UP BANNER ── */\n    .next-up {\n      margin: 16px 24px;\n      background: linear-gradient(135deg, #1a1508 0%, #2a1f06 50%, #1a1508 100%);\n      border: 1px solid #c9a84c40;\n      border-radius: 16px;\n      padding: 18px 20px;\n      position: relative;\n      overflow: hidden;\n    }\n\n    .next-up::before {\n      content: '''';\n      position: absolute;\n      top: 0; left: 0; right: 0;\n      height: 1px;\n      background: linear-gradient(90deg, transparent, #c9a84c80, transparent);\n    }\n\n    .next-up-label {\n      font-size: 10px;\n      letter-spacing: 0.15em;\n      text-transform: uppercase;\n      color: #c9a84c;\n      font-weight: 500;\n      margin-bottom: 10px;\n    }\n\n    .next-up-content {\n      display: flex;\n      justify-content: space-between;\n      align-items: center;\n    }\n\n    .next-up-name {\n      font-family: ''Cormorant Garamond'', serif;\n      font-size: 26px;\n      font-weight: 400;\n      color: #f5f0e8;\n      line-height: 1;\n    }\n\n    .next-up-sub {\n      font-size: 12px;\n      color: #9a8f7e;\n      margin-top: 4px;\n      font-weight: 300;\n    }\n\n    .countdown-big {\n      text-align: right;\n    }\n\n    .countdown-big .days {\n      font-family: ''Cormorant Garamond'', serif;\n      font-size: 42px;\n      font-weight: 300;\n      color: #c9a84c;\n      line-height: 1;\n    }\n\n    .countdown-big .days-label {\n      font-size: 10px;\n      letter-spacing: 0.12em;\n      text-transform: uppercase;\n      color: #c9a84c80;\n      font-weight: 500;\n    }\n\n    /* ── SECTION TITLE ── */\n    .section-title {\n      padding: 12px 24px 12px;\n      font-size: 10px;\n      letter-spacing: 0.15em;\n      text-transform: uppercase;\n      color: #9a8f7e;\n      font-weight: 500;\n    }\n\n    /* ── BIRTHDAY CARDS ── */\n    .cards {\n      padding: 0 24px;\n      display: flex;\n      flex-direction: column;\n      gap: 12px;\n    }\n\n    .card {\n      background: #13131a;\n      border: 1px solid #2a2a35;\n      border-radius: 16px;\n      padding: 18px 20px;\n      display: flex;\n      align-items: center;\n      gap: 16px;\n      position: relative;\n      overflow: hidden;\n      transition: border-color 0.2s;\n    }\n\n    .card:active {\n      border-color: #c9a84c60;\n    }\n\n    .card::after {\n      content: '''';\n      position: absolute;\n      left: 0; top: 0; bottom: 0;\n      width: 3px;\n      background: linear-gradient(180deg, #c9a84c, #e8d5a3);\n      opacity: 0;\n      transition: opacity 0.2s;\n    }\n\n    .card.soon::after {\n      opacity: 1;\n    }\n\n    .card.soon {\n      border-color: #c9a84c30;\n    }\n\n    .card-avatar {\n      width: 46px;\n      height: 46px;\n      border-radius: 50%;\n      display: flex;\n      align-items: center;\n      justify-content: center;\n      font-size: 18px;\n      font-weight: 400;\n      flex-shrink: 0;\n      font-family: ''Cormorant Garamond'', serif;\n    }\n\n    .card-info { flex: 1; }\n\n    .card-name {\n      font-family: ''Cormorant Garamond'', serif;\n      font-size: 20px;\n      font-weight: 400;\n      color: #f5f0e8;\n      line-height: 1.1;\n    }\n\n    .card-meta {\n      font-size: 12px;\n      color: #9a8f7e;\n      margin-top: 3px;\n      font-weight: 300;\n    }\n\n    .card-right { text-align: right; }\n\n    .card-days {\n      font-family: ''Cormorant Garamond'', serif;\n      font-size: 28px;\n      font-weight: 300;\n      color: #f5f0e8;\n      line-height: 1;\n    }\n\n    .card-days.gold { color: #c9a84c; }\n\n    .card-days-label {\n      font-size: 10px;\n      letter-spacing: 0.1em;\n      text-transform: uppercase;\n      color: #9a8f7e60;\n      font-weight: 500;\n    }\n\n    /* ── FAB ── */\n    .fab {\n      position: fixed;\n      bottom: 32px;\n      right: 24px;\n      width: 56px;\n      height: 56px;\n      border-radius: 50%;\n      background: linear-gradient(135deg, #c9a84c, #e8d5a3);\n      display: flex;\n      align-items: center;\n      justify-content: center;\n      font-size: 26px;\n      color: #0d0d0f;\n      box-shadow: 0 4px 24px #c9a84c40;\n      cursor: pointer;\n      transition: transform 0.15s, box-shadow 0.15s;\n      z-index: 100;\n    }\n\n    .fab:active {\n      transform: scale(0.93);\n      box-shadow: 0 2px 12px #c9a84c30;\n    }\n\n    /* ── BOTTOM NAV ── */\n    .bottom-nav {\n      position: fixed;\n      bottom: 0; left: 50%;\n      transform: translateX(-50%);\n      width: 100%;\n      max-width: 430px;\n      background: #0d0d0f;\n      border-top: 1px solid #2a2a35;\n      display: flex;\n      padding: 10px 0 20px;\n    }\n\n    .nav-item {\n      flex: 1;\n      display: flex;\n      flex-direction: column;\n      align-items: center;\n      gap: 4px;\n      cursor: pointer;\n    }\n\n    .nav-icon { font-size: 20px; opacity: 0.4; }\n    .nav-label { font-size: 10px; letter-spacing: 0.08em; color: #9a8f7e; opacity: 0.5; text-transform: uppercase; }\n\n    .nav-item.active .nav-icon { opacity: 1; }\n    .nav-item.active .nav-label { opacity: 1; color: #c9a84c; }\n\n    /* ── MONTH TAG ── */\n    .month-divider {\n      padding: 16px 24px 8px;\n      font-size: 10px;\n      letter-spacing: 0.15em;\n      text-transform: uppercase;\n      color: #c9a84c60;\n      font-weight: 500;\n    }\n\n    /* ── BOTTOM SPACER ── */\n    .spacer { height: 100px; }\n\n    /* ── SHIMMER ANIMATION ── */\n    @keyframes shimmer {\n      0% { opacity: 0.6; }\n      50% { opacity: 1; }\n      100% { opacity: 0.6; }\n    }\n\n    .next-up-label { animation: shimmer 3s ease-in-out infinite; }\n  </style>\n</head>\n<body>\n\n  <!-- Status Bar -->\n  <div class=\"status-bar\">\n    <span id=\"time\">9:41</span>\n    <span>●●●</span>\n  </div>\n\n  <!-- Header -->\n  <div class=\"header\">\n    <div class=\"header-left\">\n      <h1>Celebrations</h1>\n      <p id=\"today-date\">Loading...</p>\n    </div>\n    <div class=\"avatar\">J</div>\n  </div>\n\n  <!-- Next Up Banner -->\n  <div class=\"next-up\">\n    <div class=\"next-up-label\">✦ Next Celebration</div>\n    <div class=\"next-up-content\">\n      <div>\n        <div class=\"next-up-name\" id=\"next-name\">—</div>\n        <div class=\"next-up-sub\" id=\"next-sub\">—</div>\n      </div>\n      <div class=\"countdown-big\">\n        <div class=\"days\" id=\"next-days\">—</div>\n        <div class=\"days-label\">days away</div>\n      </div>\n    </div>\n  </div>\n\n  <!-- Section -->\n  <div class=\"section-title\">Upcoming</div>\n\n  <!-- Cards -->\n  <div class=\"cards\" id=\"cards-container\"></div>\n\n  <div class=\"spacer\"></div>\n\n  <!-- FAB -->\n  <div class=\"fab\">+</div>\n\n  <!-- Bottom Nav -->\n  <div class=\"bottom-nav\">\n    <div class=\"nav-item active\">\n      <div class=\"nav-icon\">✦</div>\n      <div class=\"nav-label\">Home</div>\n    </div>\n    <div class=\"nav-item\">\n      <div class=\"nav-icon\">◎</div>\n      <div class=\"nav-label\">Calendar</div>\n    </div>\n    <div class=\"nav-item\">\n      <div class=\"nav-icon\">♡</div>\n      <div class=\"nav-label\">People</div>\n    </div>\n    <div class=\"nav-item\">\n      <div class=\"nav-icon\">◈</div>\n      <div class=\"nav-label\">Ideas</div>\n    </div>\n  </div>\n\n<script>\n  // ── SEED DATA ──\n  const people = [\n    { name: \"Sophia\",   emoji: \"S\", color: \"#1e1a2e\", text: \"#c4b0e8\", month: 6,  day: 18, relation: \"Best friend\" },\n    { name: \"Marcus\",   emoji: \"M\", color: \"#1a1e2e\", text: \"#a0b8e8\", month: 6,  day: 28, relation: \"Brother\" },\n    { name: \"Elena\",    emoji: \"E\", color: \"#1e2a1a\", text: \"#a0d4a0\", month: 7,  day: 4,  relation: \"College friend\" },\n    { name: \"James\",    emoji: \"J\", color: \"#2e1a1a\", text: \"#e8a0a0\", month: 7,  day: 19, relation: \"Partner\" },\n    { name: \"Priya\",    emoji: \"P\", color: \"#2e1e1a\", text: \"#e8c4a0\", month: 8,  day: 2,  relation: \"Work bestie\" },\n    { name: \"Luca\",     emoji: \"L\", color: \"#1a2a2e\", text: \"#a0d4e8\", month: 8,  day: 15, relation: \"Cousin\" },\n    { name: \"Amara\",    emoji: \"A\", color: \"#2a1e2e\", text: \"#d4a0e8\", month: 9,  day: 7,  relation: \"Neighbor\" },\n  ];\n\n  function daysUntilBirthday(month, day) {\n    const today = new Date();\n    const thisYear = today.getFullYear();\n    let bday = new Date(thisYear, month - 1, day);\n    if (bday < today) bday = new Date(thisYear + 1, month - 1, day);\n    const diff = Math.ceil((bday - today) / (1000 * 60 * 60 * 24));\n    return diff;\n  }\n\n  function formatDate(month, day) {\n    const months = [\"Jan\",\"Feb\",\"Mar\",\"Apr\",\"May\",\"Jun\",\"Jul\",\"Aug\",\"Sep\",\"Oct\",\"Nov\",\"Dec\"];\n    return `${months[month - 1]} ${day}`;\n  }\n\n  function formatToday() {\n    const d = new Date();\n    const days = [\"Sunday\",\"Monday\",\"Tuesday\",\"Wednesday\",\"Thursday\",\"Friday\",\"Saturday\"];\n    const months = [\"January\",\"February\",\"March\",\"April\",\"May\",\"June\",\n                    \"July\",\"August\",\"September\",\"October\",\"November\",\"December\"];\n    return `${days[d.getDay()]}, ${months[d.getMonth()]} ${d.getDate()}`;\n  }\n\n  function updateTime() {\n    const d = new Date();\n    const h = d.getHours();\n    const m = String(d.getMinutes()).padStart(2, ''0'');\n    document.getElementById(''time'').textContent = `${h}:${m}`;\n  }\n\n  // Sort by days until birthday\n  const sorted = people\n    .map(p => ({ ...p, days: daysUntilBirthday(p.month, p.day) }))\n    .sort((a, b) => a.days - b.days);\n\n  // Next up\n  const next = sorted[0];\n  document.getElementById(''next-name'').textContent = next.name;\n  document.getElementById(''next-sub'').textContent = `${next.relation} · ${formatDate(next.month, next.day)}`;\n  document.getElementById(''next-days'').textContent = next.days;\n  document.getElementById(''today-date'').textContent = formatToday();\n\n  // Render cards\n  const container = document.getElementById(''cards-container'');\n  let lastMonth = null;\n\n  sorted.forEach((p, i) => {\n    if (i === 0) return; // skip next-up, already shown\n\n    if (p.month !== lastMonth) {\n      const divider = document.createElement(''div'');\n      divider.className = ''month-divider'';\n      const monthNames = [\"January\",\"February\",\"March\",\"April\",\"May\",\"June\",\n                          \"July\",\"August\",\"September\",\"October\",\"November\",\"December\"];\n      divider.textContent = monthNames[p.month - 1];\n      container.appendChild(divider);\n      lastMonth = p.month;\n    }\n\n    const soon = p.days <= 14;\n    const card = document.createElement(''div'');\n    card.className = `card${soon ? '' soon'' : ''''}`;\n    card.innerHTML = `\n      <div class=\"card-avatar\" style=\"background:${p.color}; color:${p.text}\">${p.emoji}</div>\n      <div class=\"card-info\">\n        <div class=\"card-name\">${p.name}</div>\n        <div class=\"card-meta\">${p.relation} &nbsp;·&nbsp; ${formatDate(p.month, p.day)}</div>\n      </div>\n      <div class=\"card-right\">\n        <div class=\"card-days${soon ? '' gold'' : ''''}\">${p.days}</div>\n        <div class=\"card-days-label\">days</div>\n      </div>\n    `;\n    container.appendChild(card);\n  });\n\n  updateTime();\n  setInterval(updateTime, 10000);\n</script>\n</body>\n</html>"}

