INSERT INTO "chat_messages" ("id", "session_id", "role", "content", "intent_type", "catch_payload", "created_at", "execution_time_ms", "input_tokens", "output_tokens", "cost_usd", "run_status", "run_summary", "run_actions", "run_artifacts") VALUES (668, 188, 'assistant', 'ARTIFACT: {"type":"html","title":"Birthday Celebration Tracker — Mobile Mockup","content":"<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>Birthday Tracker</title>\n<style>\n  * { margin: 0; padding: 0; box-sizing: border-box; }\n  \n  body {\n    background: #0a0a0a;\n    display: flex;\n    justify-content: center;\n    align-items: center;\n    min-height: 100vh;\n    font-family: -apple-system, BlinkMacSystemFont, ''SF Pro Display'', ''Segoe UI'', sans-serif;\n  }\n\n  .phone-frame {\n    width: 390px;\n    height: 844px;\n    background: #111111;\n    border-radius: 54px;\n    border: 2px solid #2a2a2a;\n    box-shadow: 0 0 0 1px #1a1a1a, 0 40px 80px rgba(0,0,0,0.8), inset 0 0 0 1px #333;\n    position: relative;\n    overflow: hidden;\n  }\n\n  /* Notch */\n  .notch {\n    position: absolute;\n    top: 0;\n    left: 50%;\n    transform: translateX(-50%);\n    width: 126px;\n    height: 37px;\n    background: #0a0a0a;\n    border-radius: 0 0 20px 20px;\n    z-index: 100;\n  }\n\n  .screen {\n    width: 100%;\n    height: 100%;\n    background: #0d0d0d;\n    border-radius: 52px;\n    overflow: hidden;\n    display: flex;\n    flex-direction: column;\n  }\n\n  /* Status bar */\n  .status-bar {\n    padding: 14px 28px 0;\n    display: flex;\n    justify-content: space-between;\n    align-items: center;\n    flex-shrink: 0;\n    margin-top: 10px;\n  }\n\n  .status-time {\n    font-size: 15px;\n    font-weight: 600;\n    color: #ffffff;\n    letter-spacing: -0.3px;\n  }\n\n  .status-icons {\n    display: flex;\n    gap: 6px;\n    align-items: center;\n  }\n\n  .status-icons svg {\n    width: 16px;\n    height: 12px;\n    fill: white;\n  }\n\n  /* Scrollable content */\n  .scroll-content {\n    flex: 1;\n    overflow-y: auto;\n    padding-bottom: 90px;\n    scrollbar-width: none;\n  }\n\n  .scroll-content::-webkit-scrollbar { display: none; }\n\n  /* Header */\n  .header {\n    padding: 20px 24px 16px;\n  }\n\n  .header-top {\n    display: flex;\n    justify-content: space-between;\n    align-items: flex-start;\n    margin-bottom: 4px;\n  }\n\n  .greeting {\n    font-size: 13px;\n    color: #666;\n    letter-spacing: 0.5px;\n    text-transform: uppercase;\n    font-weight: 500;\n  }\n\n  .avatar {\n    width: 36px;\n    height: 36px;\n    border-radius: 50%;\n    background: linear-gradient(135deg, #c9a84c, #f5d280);\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    font-size: 14px;\n    font-weight: 700;\n    color: #0d0d0d;\n  }\n\n  .header-title {\n    font-size: 28px;\n    font-weight: 700;\n    color: #ffffff;\n    letter-spacing: -0.8px;\n    line-height: 1.1;\n  }\n\n  .gold { color: #c9a84c; }\n\n  /* Month selector */\n  .month-strip {\n    padding: 0 24px 20px;\n    display: flex;\n    gap: 8px;\n    overflow-x: auto;\n    scrollbar-width: none;\n  }\n\n  .month-strip::-webkit-scrollbar { display: none; }\n\n  .month-chip {\n    flex-shrink: 0;\n    padding: 7px 16px;\n    border-radius: 20px;\n    font-size: 13px;\n    font-weight: 500;\n    background: #1a1a1a;\n    color: #666;\n    border: 1px solid #252525;\n    cursor: pointer;\n    white-space: nowrap;\n  }\n\n  .month-chip.active {\n    background: linear-gradient(135deg, #c9a84c, #f5d280);\n    color: #0d0d0d;\n    border-color: transparent;\n    font-weight: 700;\n  }\n\n  /* Featured card */\n  .featured-section {\n    padding: 0 24px 24px;\n  }\n\n  .section-label {\n    font-size: 11px;\n    font-weight: 600;\n    color: #555;\n    letter-spacing: 1.5px;\n    text-transform: uppercase;\n    margin-bottom: 14px;\n  }\n\n  .featured-card {\n    background: linear-gradient(145deg, #1a1508, #231c0a);\n    border: 1px solid #3a2f0e;\n    border-radius: 24px;\n    padding: 24px;\n    position: relative;\n    overflow: hidden;\n  }\n\n  .featured-card::before {\n    content: '''';\n    position: absolute;\n    top: -40px;\n    right: -40px;\n    width: 140px;\n    height: 140px;\n    background: radial-gradient(circle, rgba(201,168,76,0.15) 0%, transparent 70%);\n    pointer-events: none;\n  }\n\n  .featured-badge {\n    display: inline-flex;\n    align-items: center;\n    gap: 5px;\n    background: rgba(201,168,76,0.15);\n    border: 1px solid rgba(201,168,76,0.3);\n    border-radius: 20px;\n    padding: 4px 10px;\n    font-size: 11px;\n    font-weight: 600;\n    color: #c9a84c;\n    letter-spacing: 0.5px;\n    margin-bottom: 16px;\n  }\n\n  .featured-name {\n    font-size: 26px;\n    font-weight: 700;\n    color: #ffffff;\n    letter-spacing: -0.5px;\n    margin-bottom: 4px;\n  }\n\n  .featured-date {\n    font-size: 14px;\n    color: #888;\n    margin-bottom: 20px;\n  }\n\n  .countdown-row {\n    display: flex;\n    gap: 12px;\n  }\n\n  .countdown-unit {\n    text-align: center;\n  }\n\n  .countdown-num {\n    display: block;\n    font-size: 28px;\n    font-weight: 800;\n    color: #c9a84c;\n    letter-spacing: -1px;\n    line-height: 1;\n  }\n\n  .countdown-label {\n    display: block;\n    font-size: 10px;\n    color: #666;\n    text-transform: uppercase;\n    letter-spacing: 0.8px;\n    margin-top: 4px;\n    font-weight: 500;\n  }\n\n  .countdown-divider {\n    font-size: 24px;\n    color: #3a3a3a;\n    align-self: flex-start;\n    margin-top: 2px;\n    font-weight: 300;\n  }\n\n  .featured-emoji {\n    position: absolute;\n    right: 24px;\n    top: 50%;\n    transform: translateY(-50%);\n    font-size: 56px;\n    opacity: 0.4;\n  }\n\n  /* Birthday list */\n  .list-section {\n    padding: 0 24px;\n  }\n\n  .birthday-card {\n    background: #161616;\n    border: 1px solid #222;\n    border-radius: 18px;\n    padding: 16px 18px;\n    margin-bottom: 10px;\n    display: flex;\n    align-items: center;\n    gap: 14px;\n    position: relative;\n    overflow: hidden;\n  }\n\n  .birthday-card.soon {\n    border-color: rgba(201,168,76,0.25);\n    background: linear-gradient(135deg, #161208, #161616);\n  }\n\n  .birthday-card.soon::after {\n    content: '''';\n    position: absolute;\n    left: 0;\n    top: 0;\n    bottom: 0;\n    width: 3px;\n    background: linear-gradient(180deg, #c9a84c, #f5d280);\n    border-radius: 3px 0 0 3px;\n  }\n\n  .card-avatar {\n    width: 46px;\n    height: 46px;\n    border-radius: 50%;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    font-size: 18px;\n    font-weight: 700;\n    flex-shrink: 0;\n    position: relative;\n  }\n\n  .card-avatar-text {\n    width: 46px;\n    height: 46px;\n    border-radius: 50%;\n    background: #252525;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    font-size: 16px;\n    font-weight: 700;\n    color: #888;\n    flex-shrink: 0;\n  }\n\n  .card-avatar-text.gold-av {\n    background: linear-gradient(135deg, #c9a84c22, #c9a84c44);\n    color: #c9a84c;\n    border: 1px solid rgba(201,168,76,0.3);\n  }\n\n  .card-info {\n    flex: 1;\n    min-width: 0;\n  }\n\n  .card-name {\n    font-size: 15px;\n    font-weight: 600;\n    color: #f0f0f0;\n    letter-spacing: -0.2px;\n    white-space: nowrap;\n    overflow: hidden;\n    text-overflow: ellipsis;\n  }\n\n  .card-date {\n    font-size: 12px;\n    color: #555;\n    margin-top: 2px;\n  }\n\n  .card-right {\n    text-align: right;\n    flex-shrink: 0;\n  }\n\n  .days-num {\n    font-size: 22px;\n    font-weight: 800;\n    color: #ffffff;\n    letter-spacing: -0.8px;\n    line-height: 1;\n  }\n\n  .days-num.gold-text { color: #c9a84c; }\n\n  .days-label {\n    font-size: 11px;\n    color: #555;\n    letter-spacing: 0.3px;\n  }\n\n  .relation-tag {\n    display: inline-block;\n    padding: 2px 8px;\n    border-radius: 8px;\n    font-size: 10px;\n    font-weight: 600;\n    background: #1e1e1e;\n    color: #666;\n    border: 1px solid #2a2a2a;\n    margin-top: 4px;\n    letter-spacing: 0.3px;\n  }\n\n  .relation-tag.gold-tag {\n    background: rgba(201,168,76,0.1);\n    color: #c9a84c;\n    border-color: rgba(201,168,76,0.2);\n  }\n\n  /* Bottom nav */\n  .bottom-nav {\n    position: absolute;\n    bottom: 0;\n    left: 0;\n    right: 0;\n    height: 90px;\n    background: linear-gradient(180deg, transparent 0%, #0d0d0d 30%);\n    display: flex;\n    align-items: flex-end;\n    padding-bottom: 28px;\n    border-radius: 0 0 52px 52px;\n  }\n\n  .nav-bar {\n    width: calc(100% - 32px);\n    margin: 0 16px;\n    background: #161616;\n    border: 1px solid #252525;\n    border-radius: 28px;\n    padding: 12px 24px;\n    display: flex;\n    justify-content: space-between;\n    align-items: center;\n  }\n\n  .nav-item {\n    display: flex;\n    flex-direction: column;\n    align-items: center;\n    gap: 4px;\n    cursor: pointer;\n  }\n\n  .nav-icon {\n    font-size: 20px;\n    opacity: 0.4;\n  }\n\n  .nav-icon.active { opacity: 1; }\n\n  .nav-dot {\n    width: 4px;\n    height: 4px;\n    border-radius: 50%;\n    background: #c9a84c;\n  }\n\n  .nav-add {\n    width: 48px;\n    height: 48px;\n    border-radius: 50%;\n    background: linear-gradient(135deg, #c9a84c, #f5d280);\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    font-size: 24px;\n    color: #0d0d0d;\n    font-weight: 300;\n    box-shadow: 0 4px 20px rgba(201,168,76,0.4);\n    margin-top: -8px;\n    cursor: pointer;\n  }\n\n  .home-indicator {\n    position: absolute;\n    bottom: 8px;\n    left: 50%;\n    transform: translateX(-50%);\n    width: 134px;\n    height: 5px;\n    background: rgba(255,255,255,0.2);\n    border-radius: 3px;\n  }\n\n  /* Side buttons */\n  .side-button {\n    position: absolute;\n    right: -3px;\n    width: 4px;\n    border-radius: 2px 0 0 2px;\n    background: #222;\n  }\n\n  .power-btn { top: 220px; height: 80px; }\n\n  .left-button {\n    position: absolute;\n    left: -3px;\n    width: 4px;\n    border-radius: 0 2px 2px 0;\n    background: #222;\n  }\n\n  .vol-up { top: 160px; height: 50px; }\n  .vol-down { top: 220px; height: 50px; }\n  .mute { top: 130px; height: 30px; }\n</style>\n</head>\n<body>\n\n<div class=\"phone-frame\">\n  <div class=\"notch\"></div>\n  \n  <!-- Side buttons -->\n  <div class=\"left-button mute\"></div>\n  <div class=\"left-button vol-up\"></div>\n  <div class=\"left-button vol-down\"></div>\n  <div class=\"side-button power-btn\"></div>\n\n  <div class=\"screen\">\n    <!-- Status bar -->\n    <div class=\"status-bar\">\n      <span class=\"status-time\" id=\"status-time\">9:41</span>\n      <div class=\"status-icons\">\n        <svg viewBox=\"0 0 24 16\"><rect x=\"0\" y=\"4\" width=\"3\" height=\"12\" rx=\"1\"/><rect x=\"5\" y=\"2\" width=\"3\" height=\"14\" rx=\"1\"/><rect x=\"10\" y=\"0\" width=\"3\" height=\"16\" rx=\"1\"/><rect x=\"15\" y=\"3\" width=\"3\" height=\"10\" rx=\"1\" opacity=\"0.3\"/></svg>\n        <svg viewBox=\"0 0 16 12\" style=\"width:14px\"><path d=\"M8 2.4C5.6 2.4 3.5 3.4 2 5L0 3C2.1 1.1 4.9 0 8 0s5.9 1.1 8 3l-2 2C12.5 3.4 10.4 2.4 8 2.4z\" opacity=\"0.3\"/><path d=\"M8 5.6c-1.5 0-2.8.6-3.8 1.5L2.5 5.4C3.9 4.1 5.9 3.3 8 3.3s4.1.8 5.5 2.1L11.8 7.1C10.8 6.2 9.5 5.6 8 5.6z\" opacity=\"0.6\"/><path d=\"M8 8.8c-.8 0-1.5.3-2 .8L4.5 8C5.5 7.1 6.7 6.5 8 6.5s2.5.6 3.5 1.5L10 9.6c-.5-.5-1.2-.8-2-.8z\"/><circle cx=\"8\" cy=\"12\" r=\"1.5\"/></svg>\n        <svg viewBox=\"0 0 25 12\" style=\"width:25px;height:12px;fill:none;stroke:white;stroke-width:1\">\n          <rect x=\"0.5\" y=\"0.5\" width=\"21\" height=\"11\" rx=\"3.5\" stroke=\"white\" stroke-opacity=\"0.35\"/>\n          <rect x=\"2\" y=\"2\" width=\"17\" height=\"8\" rx=\"2\" fill=\"white\"/>\n          <path d=\"M23 4v4a2 2 0 000-4z\" fill=\"white\" stroke=\"none\"/>\n        </svg>\n      </div>\n    </div>\n\n    <div class=\"scroll-content\">\n      <!-- Header -->\n      <div class=\"header\">\n        <div class=\"header-top\">\n          <span class=\"greeting\">Celebrations</span>\n          <div class=\"avatar\">J</div>\n        </div>\n        <div class=\"header-title\">Upcoming <span class=\"gold\">Birthdays</span></div>\n      </div>\n\n      <!-- Month strip -->\n      <div class=\"month-strip\">\n        <div class=\"month-chip active\">All</div>\n        <div class=\"month-chip\">Jun</div>\n        <div class=\"month-chip\">Jul</div>\n        <div class=\"month-chip\">Aug</div>\n        <div class=\"month-chip\">Sep</div>\n        <div class=\"month-chip\">Oct</div>\n        <div class=\"month-chip\">Nov</div>\n        <div class=\"month-chip\">Dec</div>\n      </div>\n\n      <!-- Featured card -->\n      <div class=\"featured-section\">\n        <div class=\"section-label\">Coming Up Next</div>\n        <div class=\"featured-card\">\n          <div class=\"featured-badge\">🎂 Soonest</div>\n          <div class=\"featured-name\" id=\"feat-name\">Sophia</div>\n          <div class=\"featured-date\" id=\"feat-date\">June 18 · Turning 28</div>\n          <div class=\"countdown-row\">\n            <div class=\"countdown-unit\">\n              <span class=\"countdown-num\" id=\"feat-days\">7</span>\n              <span class=\"countdown-label\">Days</span>\n            </div>\n            <span class=\"countdown-divider\">:</span>\n            <div class=\"countdown-unit\">\n              <span class=\"countdown-num\" id=\"feat-hours\">14</span>\n              <span class=\"countdown-label\">Hours</span>\n            </div>\n            <span class=\"countdown-divider\">:</span>\n            <div class=\"countdown-unit\">\n              <span class=\"countdown-num\" id=\"feat-mins\">32</span>\n              <span class=\"countdown-label\">Mins</span>\n            </div>\n          </div>\n          <div class=\"featured-emoji\">🎂</div>\n        </div>\n      </div>\n\n      <!-- List -->\n      <div class=\"list-section\">\n        <div class=\"section-label\">All Upcoming</div>\n\n        <div class=\"birthday-card soon\" id=\"card-0\">\n          <div class=\"card-avatar-text gold-av\" id=\"init-0\">S</div>\n          <div class=\"card-info\">\n            <div class=\"card-name\">Sophia Carter</div>\n            <div class=\"card-date\" id=\"date-0\">June 18</div>\n            <span class=\"relation-tag gold-tag\">Best Friend</span>\n          </div>\n          <div class=\"card-right\">\n            <div class=\"days-num gold-text\" id=\"days-0\">7</div>\n            <div class=\"days-label\">days</div>\n          </div>\n        </div>\n\n        <div class=\"birthday-card\" id=\"card-1\">\n          <div class=\"card-avatar-text\" id=\"init-1\">M</div>\n          <div class=\"card-info\">\n            <div class=\"card-name\">Marcus Lee</div>\n            <div class=\"card-date\" id=\"date-1\">June 25</div>\n            <span class=\"relation-tag\">Brother</span>\n          </div>\n          <div class=\"card-right\">\n            <div class=\"days-num\" id=\"days-1\">14</div>\n            <div class=\"days-label\">days</div>\n          </div>\n        </div>\n\n        <div class=\"birthday-card\" id=\"card-2\">\n          <div class=\"card-avatar-text\" id=\"init-2\">A</div>\n          <div class=\"card-info\">\n            <div class=\"card-name\">Amara Osei</div>\n            <div class=\"card-date\" id=\"date-2\">July 4</div>\n            <span class=\"relation-tag\">Colleague</span>\n          </div>\n          <div class=\"card-right\">\n            <div class=\"days-num\" id=\"days-2\">23</div>\n            <div class=\"days-label\">days</div>\n          </div>\n        </div>\n\n        <div class=\"birthday-card\" id=\"card-3\">\n          <div class=\"card-avatar-text\" id=\"init-3\">D</div>\n          <div class=\"card-info\">\n            <div class=\"card-name\">David Okafor</div>\n            <div class=\"card-date\" id=\"date-3\">July 19</div>\n            <span class=\"relation-tag\">Cousin</span>\n          </div>\n          <div class=\"card-right\">\n            <div class=\"days-num\" id=\"days-3\">38</div>\n            <div class=\"days-label\">days</div>\n          </div>\n        </div>\n\n        <div class=\"birthday-card\" id=\"card-4\">\n          <div class=\"card-avatar-text\" id=\"init-4\">R</div>\n          <div class=\"card-info\">\n            <div class=\"card-name\">Rita Mensah</div>\n            <div class=\"card-date\" id=\"date-4\">August 3</div>\n            <span class=\"relation-tag\">Mom</span>\n          </div>\n          <div class=\"card-right\">\n            <div class=\"days-num\" id=\"days-4\">53</div>\n            <div class=\"days-label\">days</div>\n          </div>\n        </div>\n\n        <div class=\"birthday-card\" id=\"card-5\">\n          <div class=\"card-avatar-text\" id=\"init-5\">T</div>\n          <div class=\"card-info\">\n            <div class=\"card-name\">Temi Adeyemi</div>\n            <div class=\"card-date\" id=\"date-5\">September 12</div>\n            <span class=\"relation-tag\">Friend</span>\n          </div>\n          <div class=\"card-right\">\n            <div class=\"days-num\" id=\"days-5\">93</div>\n            <div class=\"days-label\">days</div>\n          </div>\n        </div>\n\n      </div>\n    </div>\n\n    <!-- Bottom nav -->\n    <div class=\"bottom-nav\">\n      <div class=\"nav-bar\">\n        <div class=\"nav-item\">\n          <span class=\"nav-icon active\">🏠</span>\n          <div class=\"nav-dot\"></div>\n        </div>\n        <div class=\"nav-item\">\n          <span class=\"nav-icon\">🔍</span>\n        </div>\n        <div class=\"nav-add\">+</div>\n        <div class=\"nav-item\">\n          <span class=\"nav-icon\">🎁</span>\n        </div>\n        <div class=\"nav-item\">\n          <span class=\"nav-icon\">👤</span>\n        </div>\n      </div>\n    </div>\n\n    <div class=\"home-indicator\"></div>\n  </div>\n</div>\n\n<script>\n  // Live clock\n  function updateClock() {\n    const now = new Date();\n    let h = now.getHours();\n    let m = now.getMinutes();\n    const ampm = h >= 12 ? ''PM'' : ''AM'';\n    h = h % 12 || 12;\n    document.getElementById(''status-time'').textContent = h + '':'' + String(m).padStart(2,''0'');\n  }\n  updateClock();\n  setInterval(updateClock, 1000);\n\n  // People data\n  const people = [\n    { name: ''Sophia Carter'', month: 6, day: 18, age: 28, relation: ''Best Friend'' },\n    { name: ''Marcus Lee'',    month: 6, day: 25, age: 31, relation: ''Brother'' },\n    { name: ''Amara Osei'',   month: 7, day: 4,  age: 26, relation: ''Colleague'' },\n    { name: ''David Okafor'', month: 7, day: 19, age: 34, relation: ''Cousin'' },\n    { name: ''Rita Mensah'',  month: 8, day: 3,  age: 55, relation: ''Mom'' },\n    { name: ''Temi Adeyemi'', month: 9, day: 12, age: 29, relation: ''Friend'' },\n  ];\n\n  function daysUntil(month, day) {\n    const now = new Date();\n    const target = new Date(now.getFullYear(), month - 1, day);\n    if (target < now) target.setFullYear(now.getFullYear() + 1);\n    const diff = target - now;\n    return Math.ceil(diff / (1000 * 60 * 60 * 24));\n  }\n\n  function msUntil(month, day) {\n    const now = new Date();\n    const target = new Date(now.getFullYear(), month - 1, day);\n    if (target < now) target.setFullYear(now.getFullYear() + 1);\n    return target - now;\n  }\n\n  // Update countdown cards\n  function updateCountdowns() {\n    people.forEach((p, i) => {\n      const days = daysUntil(p.month, p.day);\n      const el = document.getElementById(''days-'' + i);\n      if (el) el.textContent = days;\n      const card = document.getElementById(''card-'' + i);\n      if (card) {\n        if (days <= 14) {\n          card.classList.add(''soon'');\n          const daysEl = document.getElementById(''days-'' + i);\n          if (daysEl) daysEl.classList.add(''gold-text'');\n          const initEl = document.getElementById(''init-'' + i);\n          if (initEl) { initEl.classList.remove(''card-avatar-text''); initEl.classList.add(''card-avatar-text'',''gold-av''); }\n        }\n      }\n    });\n\n    // Featured countdown (soonest person)\n    const soonest = people[0];\n    const ms = msUntil(soonest.month, soonest.day);\n    const totalSecs = Math.floor(ms / 1000);\n    const d = Math.floor(totalSecs / 86400);\n    const h = Math.floor((totalSecs % 86400) / 3600);\n    const m = Math.floor((totalSecs % 3600) / 60);\n    document.getElementById(''feat-days'').textContent = d;\n    document.getElementById(''feat-hours'').textContent = String(h).padStart(2,''0'');\n    document.getElementById(''feat-mins'').textContent = String(m).padStart(2,''0'');\n  }\n\n  updateCountdowns();\n  setInterval(updateCountdowns, 60000);\n\n  // Month filter (visual only)\n  document.querySelectorAll(''.month-chip'').forEach(chip => {\n    chip.addEventListener(''click'', () => {\n      document.querySelectorAll(''.month-chip'').forEach(c => c.classList.remove(''active''));\n      chip.classList.add(''active'');\n    });\n  });\n</script>\n\n</body>\n</html>"}
INSERT INTO "chat_messages" ("id", "session_id", "role", "content", "intent_type", "catch_payload", "created_at", "execution_time_ms", "input_tokens", "output_tokens", "cost_usd", "run_status", "run_summary", "run_actions", "run_artifacts") VALUES (669, 188, 'user', 'Generate a render of a dark mobile home screen with gold accents', NULL, NULL, '2026-06-11T03:35:45.498Z', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO "chat_messages" ("id", "session_id", "role", "content", "intent_type", "catch_payload", "created_at", "execution_time_ms", "input_tokens", "output_tokens", "cost_usd", "run_status", "run_summary", "run_actions", "run_artifacts") VALUES (670, 188, 'assistant', 'ARTIFACT: {"type":"html","title":"Birthday Tracker — Dark Mobile Home Screen","content":"<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"UTF-8\" />\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n  <title>Birthday Tracker</title>\n  <link href=\"https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;1,300;1,400&family=Inter:wght@300;400;500&display=swap\" rel=\"stylesheet\" />\n  <style>\n    *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }\n\n    :root {\n      --obsidian: #0a0a0c;\n      --surface: #111116;\n      --surface-2: #18181f;\n      --border: #ffffff0d;\n      --border-gold: #c9a84c30;\n      --gold: #c9a84c;\n      --gold-light: #e8d5a3;\n      --gold-dim: #c9a84c60;\n      --text: #f0ece3;\n      --text-dim: #8a8070;\n      --text-dimmer: #4a4540;\n    }\n\n    body {\n      background: var(--obsidian);\n      color: var(--text);\n      font-family: ''Inter'', sans-serif;\n      min-height: 100vh;\n      max-width: 390px;\n      margin: 0 auto;\n      overflow-x: hidden;\n      position: relative;\n    }\n\n    /* ── AMBIENT GLOW ── */\n    .ambient {\n      position: fixed;\n      top: -120px;\n      left: 50%;\n      transform: translateX(-50%);\n      width: 500px;\n      height: 400px;\n      background: radial-gradient(ellipse at center, #c9a84c08 0%, transparent 70%);\n      pointer-events: none;\n      z-index: 0;\n    }\n\n    /* ── STATUS BAR ── */\n    .status-bar {\n      position: relative;\n      z-index: 10;\n      display: flex;\n      justify-content: space-between;\n      align-items: center;\n      padding: 14px 28px 6px;\n    }\n    .status-time {\n      font-size: 15px;\n      font-weight: 500;\n      letter-spacing: 0.01em;\n      color: var(--text);\n    }\n    .status-icons {\n      display: flex;\n      gap: 6px;\n      align-items: center;\n    }\n    .status-icons span {\n      font-size: 13px;\n      color: var(--text);\n      opacity: 0.8;\n    }\n\n    /* ── HEADER ── */\n    .header {\n      position: relative;\n      z-index: 10;\n      padding: 18px 24px 0;\n      display: flex;\n      justify-content: space-between;\n      align-items: center;\n    }\n    .header-title {\n      font-family: ''Cormorant Garamond'', serif;\n      font-size: 34px;\n      font-weight: 300;\n      letter-spacing: 0.01em;\n      color: var(--text);\n      line-height: 1;\n    }\n    .header-title span {\n      color: var(--gold);\n    }\n    .header-subtitle {\n      font-size: 12px;\n      color: var(--text-dim);\n      margin-top: 5px;\n      font-weight: 300;\n      letter-spacing: 0.02em;\n    }\n    .header-avatar {\n      width: 42px;\n      height: 42px;\n      border-radius: 50%;\n      background: linear-gradient(135deg, #c9a84c, #e8d5a3);\n      display: flex;\n      align-items: center;\n      justify-content: center;\n      font-family: ''Cormorant Garamond'', serif;\n      font-size: 17px;\n      font-weight: 500;\n      color: #0a0a0c;\n      flex-shrink: 0;\n      box-shadow: 0 0 0 1px #c9a84c40, 0 4px 16px #c9a84c20;\n    }\n\n    /* ── SCROLL CONTENT ── */\n    .scroll-content {\n      position: relative;\n      z-index: 10;\n      overflow-y: auto;\n      padding-bottom: 100px;\n    }\n\n    /* ── NEXT UP HERO ── */\n    .hero {\n      margin: 20px 24px 0;\n      background: linear-gradient(145deg, #16130a 0%, #1e1a0c 40%, #16130a 100%);\n      border: 1px solid var(--border-gold);\n      border-radius: 20px;\n      padding: 22px 22px 20px;\n      position: relative;\n      overflow: hidden;\n    }\n    .hero::before {\n      content: '''';\n      position: absolute;\n      inset: 0;\n      background: radial-gradient(ellipse at 80% 20%, #c9a84c10 0%, transparent 60%);\n      pointer-events: none;\n    }\n    .hero-top-line {\n      position: absolute;\n      top: 0; left: 10%; right: 10%;\n      height: 1px;\n      background: linear-gradient(90deg, transparent, #c9a84c70, transparent);\n    }\n    .hero-tag {\n      font-size: 9px;\n      letter-spacing: 0.2em;\n      text-transform: uppercase;\n      color: var(--gold);\n      font-weight: 500;\n      margin-bottom: 14px;\n      display: flex;\n      align-items: center;\n      gap: 6px;\n    }\n    .hero-tag::before {\n      content: '''';\n      display: inline-block;\n      width: 14px;\n      height: 1px;\n      background: var(--gold);\n      opacity: 0.6;\n    }\n    .hero-body {\n      display: flex;\n      justify-content: space-between;\n      align-items: flex-end;\n    }\n    .hero-name {\n      font-family: ''Cormorant Garamond'', serif;\n      font-size: 32px;\n      font-weight: 400;\n      color: var(--text);\n      line-height: 1;\n    }\n    .hero-meta {\n      font-size: 12px;\n      color: var(--text-dim);\n      margin-top: 6px;\n      font-weight: 300;\n      display: flex;\n      align-items: center;\n      gap: 6px;\n    }\n    .hero-meta::before {\n      content: ''♡'';\n      font-size: 10px;\n      color: var(--gold-dim);\n    }\n    .hero-countdown {\n      text-align: right;\n    }\n    .hero-days {\n      font-family: ''Cormorant Garamond'', serif;\n      font-size: 52px;\n      font-weight: 300;\n      color: var(--gold);\n      line-height: 1;\n      letter-spacing: -0.02em;\n    }\n    .hero-days-label {\n      font-size: 9px;\n      letter-spacing: 0.18em;\n      text-transform: uppercase;\n      color: var(--gold-dim);\n      text-align: right;\n      margin-top: 2px;\n    }\n    .hero-progress {\n      margin-top: 18px;\n      height: 2px;\n      background: #ffffff08;\n      border-radius: 2px;\n      overflow: hidden;\n    }\n    .hero-progress-fill {\n      height: 100%;\n      background: linear-gradient(90deg, #c9a84c60, #c9a84c);\n      border-radius: 2px;\n      transition: width 1s ease;\n    }\n    .hero-progress-label {\n      display: flex;\n      justify-content: space-between;\n      margin-top: 6px;\n      font-size: 10px;\n      color: var(--text-dimmer);\n    }\n\n    /* ── STATS ROW ── */\n    .stats-row {\n      margin: 16px 24px 0;\n      display: flex;\n      gap: 10px;\n    }\n    .stat-pill {\n      flex: 1;\n      background: var(--surface);\n      border: 1px solid var(--border);\n      border-radius: 12px;\n      padding: 12px 14px;\n      text-align: center;\n    }\n    .stat-num {\n      font-family: ''Cormorant Garamond'', serif;\n      font-size: 24px;\n      font-weight: 400;\n      color: var(--text);\n      line-height: 1;\n    }\n    .stat-label {\n      font-size: 9px;\n      letter-spacing: 0.12em;\n      text-transform: uppercase;\n      color: var(--text-dim);\n      margin-top: 3px;\n    }\n\n    /* ── SECTION HEADER ── */\n    .section-header {\n      padding: 22px 24px 10px;\n      display: flex;\n      justify-content: space-between;\n      align-items: center;\n    }\n    .section-title {\n      font-size: 9px;\n      letter-spacing: 0.2em;\n      text-transform: uppercase;\n      color: var(--text-dim);\n      font-weight: 500;\n    }\n    .section-link {\n      font-size: 11px;\n      color: var(--gold-dim);\n      cursor: pointer;\n    }\n\n    /* ── BIRTHDAY CARDS ── */\n    .cards { padding: 0 24px; display: flex; flex-direction: column; gap: 10px; }\n\n    .card {\n      background: var(--surface);\n      border: 1px solid var(--border);\n      border-radius: 16px;\n      padding: 16px 18px;\n      display: flex;\n      align-items: center;\n      gap: 14px;\n      cursor: pointer;\n      transition: background 0.15s, border-color 0.15s;\n      position: relative;\n      overflow: hidden;\n    }\n    .card.hot {\n      border-color: #c9a84c25;\n      background: #13110a;\n    }\n    .card.hot::after {\n      content: '''';\n      position: absolute;\n      left: 0; top: 20%; bottom: 20%;\n      width: 2px;\n      background: linear-gradient(180deg, transparent, var(--gold), transparent);\n      border-radius: 2px;\n    }\n    .card:active { background: var(--surface-2); }\n\n    .card-avi {\n      width: 44px;\n      height: 44px;\n      border-radius: 50%;\n      display: flex;\n      align-items: center;\n      justify-content: center;\n      font-family: ''Cormorant Garamond'', serif;\n      font-size: 18px;\n      font-weight: 400;\n      flex-shrink: 0;\n      position: relative;\n    }\n    .card-avi.ring::before {\n      content: '''';\n      position: absolute;\n      inset: -2px;\n      border-radius: 50%;\n      border: 1px solid var(--gold-dim);\n    }\n\n    .card-body { flex: 1; min-width: 0; }\n    .card-name {\n      font-family: ''Cormorant Garamond'', serif;\n      font-size: 19px;\n      font-weight: 400;\n      color: var(--text);\n      line-height: 1.1;\n      white-space: nowrap;\n      overflow: hidden;\n      text-overflow: ellipsis;\n    }\n    .card-info {\n      font-size: 11px;\n      color: var(--text-dim);\n      margin-top: 3px;\n      font-weight: 300;\n    }\n\n    .card-countdown { text-align: right; flex-shrink: 0; }\n    .card-days {\n      font-family: ''Cormorant Garamond'', serif;\n      font-size: 26px;\n      font-weight: 300;\n      color: var(--text-dim);\n      line-height: 1;\n    }\n    .card-days.hot { color: var(--gold); }\n    .card-dlabel {\n      font-size: 9px;\n      letter-spacing: 0.1em;\n      text-transform: uppercase;\n      color: var(--text-dimmer);\n    }\n\n    /* ── MONTH PILL ── */\n    .month-row {\n      padding: 14px 24px 6px;\n      display: flex;\n      align-items: center;\n      gap: 10px;\n    }\n    .month-pill {\n      font-size: 9px;\n      letter-spacing: 0.18em;\n      text-transform: uppercase;\n      color: var(--gold-dim);\n      padding: 3px 10px;\n      border: 1px solid #c9a84c20;\n      border-radius: 100px;\n    }\n    .month-line {\n      flex: 1;\n      height: 1px;\n      background: var(--border);\n    }\n\n    /* ── TODAY BADGE ── */\n    .today-badge {\n      display: inline-flex;\n      align-items: center;\n      gap: 4px;\n      background: #c9a84c18;\n      border: 1px solid #c9a84c40;\n      border-radius: 100px;\n      padding: 3px 10px;\n      font-size: 9px;\n      letter-spacing: 0.12em;\n      text-transform: uppercase;\n      color: var(--gold);\n      margin-left: auto;\n    }\n\n    /* ── FAB ── */\n    .fab {\n      position: fixed;\n      bottom: 86px;\n      right: calc(50% - 195px + 16px);\n      width: 52px;\n      height: 52px;\n      border-radius: 50%;\n      background: linear-gradient(135deg, #c9a84c, #e8d5a3);\n      display: flex;\n      align-items: center;\n      justify-content: center;\n      font-size: 24px;\n      color: #0a0a0c;\n      box-shadow: 0 0 0 1px #c9a84c60, 0 8px 32px #c9a84c30;\n      cursor: pointer;\n      z-index: 100;\n      transition: transform 0.12s;\n    }\n    .fab:active { transform: scale(0.92); }\n\n    /* ── BOTTOM NAV ── */\n    .bottom-nav {\n      position: fixed;\n      bottom: 0;\n      left: 50%;\n      transform: translateX(-50%);\n      width: 100%;\n      max-width: 390px;\n      background: #0d0d10;\n      border-top: 1px solid var(--border);\n      display: flex;\n      padding: 10px 0 24px;\n      z-index: 50;\n    }\n    .nav-item {\n      flex: 1;\n      display: flex;\n      flex-direction: column;\n      align-items: center;\n      gap: 4px;\n      cursor: pointer;\n    }\n    .nav-icon { font-size: 19px; color: var(--text-dim); }\n    .nav-label { font-size: 9px; letter-spacing: 0.1em; text-transform: uppercase; color: var(--text-dim); }\n    .nav-item.active .nav-icon { color: var(--gold); }\n    .nav-item.active .nav-label { color: var(--gold); }\n    .nav-dot {\n      width: 4px; height: 4px;\n      border-radius: 50%;\n      background: var(--gold);\n      margin-top: -2px;\n    }\n\n    /* ── SCROLL BAR ── */\n    ::-webkit-scrollbar { display: none; }\n  </style>\n</head>\n<body>\n\n  <div class=\"ambient\"></div>\n\n  <!-- Status Bar -->\n  <div class=\"status-bar\">\n    <span class=\"status-time\" id=\"clock\">9:41</span>\n    <div class=\"status-icons\">\n      <span>▲▲▲</span>\n      <span>WiFi</span>\n      <span>⬛</span>\n    </div>\n  </div>\n\n  <!-- Header -->\n  <div class=\"header\">\n    <div>\n      <div class=\"header-title\">Cele<span>b</span>rations</div>\n      <div class=\"header-subtitle\" id=\"today-label\">—</div>\n    </div>\n    <div class=\"header-avatar\">J</div>\n  </div>\n\n  <!-- Scroll Content -->\n  <div class=\"scroll-content\">\n\n    <!-- Hero Card -->\n    <div class=\"hero\">\n      <div class=\"hero-top-line\"></div>\n      <div class=\"hero-tag\">Next celebration</div>\n      <div class=\"hero-body\">\n        <div>\n          <div class=\"hero-name\" id=\"hero-name\">—</div>\n          <div class=\"hero-meta\" id=\"hero-meta\">—</div>\n        </div>\n        <div class=\"hero-countdown\">\n          <div class=\"hero-days\" id=\"hero-days\">—</div>\n          <div class=\"hero-days-label\">days away</div>\n        </div>\n      </div>\n      <div class=\"hero-progress\">\n        <div class=\"hero-progress-fill\" id=\"hero-bar\" style=\"width: 0%\"></div>\n      </div>\n      <div class=\"hero-progress-label\">\n        <span id=\"hero-since\">—</span>\n        <span id=\"hero-date\">—</span>\n      </div>\n    </div>\n\n    <!-- Stats Row -->\n    <div class=\"stats-row\">\n      <div class=\"stat-pill\">\n        <div class=\"stat-num\" id=\"stat-total\">—</div>\n        <div class=\"stat-label\">Birthdays</div>\n      </div>\n      <div class=\"stat-pill\">\n        <div class=\"stat-num\" id=\"stat-this-month\">—</div>\n        <div class=\"stat-label\">This month</div>\n      </div>\n      <div class=\"stat-pill\">\n        <div class=\"stat-num\" id=\"stat-soon\">—</div>\n        <div class=\"stat-label\">This week</div>\n      </div>\n    </div>\n\n    <!-- Upcoming Section -->\n    <div class=\"section-header\">\n      <span class=\"section-title\">Upcoming</span>\n      <span class=\"section-link\">View all →</span>\n    </div>\n\n    <div class=\"cards\" id=\"cards-list\"></div>\n\n  </div>\n\n  <!-- FAB -->\n  <div class=\"fab\">+</div>\n\n  <!-- Bottom Nav -->\n  <div class=\"bottom-nav\">\n    <div class=\"nav-item active\">\n      <div class=\"nav-icon\">✦</div>\n      <div class=\"nav-dot\"></div>\n      <div class=\"nav-label\">Home</div>\n    </div>\n    <div class=\"nav-item\">\n      <div class=\"nav-icon\">◎</div>\n      <div class=\"nav-label\">Calendar</div>\n    </div>\n    <div class=\"nav-item\">\n      <div class=\"nav-icon\">♡</div>\n      <div class=\"nav-label\">People</div>\n    </div>\n    <div class=\"nav-item\">\n      <div class=\"nav-icon\">◈</div>\n      <div class=\"nav-label\">Gifts</div>\n    </div>\n  </div>\n\n<script>\n  const people = [\n    { name: ''Sophia'',   rel: ''Best friend'',   month: 6,  day: 18, bg: ''#1c1428'', fg: ''#c4aee8'' },\n    { name: ''Marcus'',   rel: ''Brother'',        month: 6,  day: 28, bg: ''#0f1826'', fg: ''#8ab4e8'' },\n    { name: ''Elena'',    rel: ''College friend'', month: 7,  day: 4,  bg: ''#0f1f14'', fg: ''#8ad4a0'' },\n    { name: ''James'',    rel: ''Partner'',        month: 7,  day: 19, bg: ''#1f0f0f'', fg: ''#e89090'' },\n    { name: ''Priya'',    rel: ''Work bestie'',    month: 8,  day: 2,  bg: ''#1f180f'', fg: ''#e8c490'' },\n    { name: ''Luca'',     rel: ''Cousin'',         month: 8,  day: 15, bg: ''#0f1c22'', fg: ''#90cce8'' },\n    { name: ''Amara'',    rel: ''Neighbour'',      month: 9,  day: 7,  bg: ''#1c0f22'', fg: ''#d490e8'' },\n    { name: ''Noah'',     rel: ''School friend'',  month: 10, day: 3,  bg: ''#221a0f'', fg: ''#e8d090'' },\n  ];\n\n  const months = [''January'',''February'',''March'',''April'',''May'',''June'',''July'',''August'',''September'',''October'',''November'',''December''];\n  const monthsShort = [''Jan'',''Feb'',''Mar'',''Apr'',''May'',''Jun'',''Jul'',''Aug'',''Sep'',''Oct'',''Nov'',''Dec''];\n  const days = [''Sunday'',''Monday'',''Tuesday'',''Wednesday'',''Thursday'',''Friday'',''Saturday''];\n\n  function daysUntil(month, day) {\n    const now = new Date();\n    const yr = now.getFullYear();\n    let bd = new Date(yr, month - 1, day);\n    if (bd <= now) bd = new Date(yr + 1, month - 1, day);\n    return Math.ceil((bd - now) / 86400000);\n  }\n\n  function progressPercent(month, day) {\n    const now = new Date();\n    const yr = now.getFullYear();\n    let next = new Date(yr, month - 1, day);\n    if (next <= now) next = new Date(yr + 1, month - 1, day);\n    let prev = new Date(next.getFullYear() - 1, month - 1, day);\n    const span = next - prev;\n    const elapsed = now - prev;\n    return Math.round((elapsed / span) * 100);\n  }\n\n  const now = new Date();\n\n  // Clock\n  function tick() {\n    const d = new Date();\n    const h = d.getHours();\n    const m = String(d.getMinutes()).padStart(2, ''0'');\n    document.getElementById(''clock'').textContent = `${h}:${m}`;\n  }\n  tick();\n  setInterval(tick, 15000);\n\n  // Today label\n  document.getElementById(''today-label'').textContent =\n    `${days[now.getDay()]}, ${months[now.getMonth()]} ${now.getDate()}`;\n\n  // Sort\n  const sorted = people\n    .map(p => ({ ...p, daysLeft: daysUntil(p.month, p.day) }))\n    .sort((a, b) => a.daysLeft - b.daysLeft);\n\n  // Hero\n  const hero = sorted[0];\n  document.getElementById(''hero-name'').textContent = hero.name;\n  document.getElementById(''hero-meta'').textContent = `${hero.rel}  ·  ${monthsShort[hero.month - 1]} ${hero.day}`;\n  document.getElementById(''hero-days'').textContent = hero.daysLeft;\n  const pct = progressPercent(hero.month, hero.day);\n  document.getElementById(''hero-bar'').style.width = pct + ''%'';\n  document.getElementById(''hero-since'').textContent = `${pct}% through the year`;\n  document.getElementById(''hero-date'').textContent = `${monthsShort[hero.month - 1]} ${hero.day}`;\n\n  // Stats\n  document.getElementById(''stat-total'').textContent = people.length;\n  const thisMonth = people.filter(p => p.month === now.getMonth() + 1).length;\n  document.getElementById(''stat-this-month'').textContent = thisMonth;\n  const thisWeek = sorted.filter(p => p.daysLeft <= 7).length;\n  document.getElementById(''stat-soon'').textContent = thisWeek;\n\n  // Cards\n  const container = document.getElementById(''cards-list'');\n  let lastMonth = null;\n\n  sorted.slice(1).forEach(p => {\n    if (p.month !== lastMonth) {\n      const row = document.createElement(''div'');\n      row.className = ''month-row'';\n      row.innerHTML = `<div class=\"month-pill\">${months[p.month - 1]}</div><div class=\"month-line\"></div>`;\n      if (p.daysLeft <= 30) {\n        row.innerHTML += `<div class=\"today-badge\">● Soon</div>`;\n      }\n      container.appendChild(row);\n      lastMonth = p.month;\n    }\n\n    const hot = p.daysLeft <= 14;\n    const card = document.createElement(''div'');\n    card.className = `card${hot ? '' hot'' : ''''}`;\n    card.innerHTML = `\n      <div class=\"card-avi${hot ? '' ring'' : ''''}\" style=\"background:${p.bg}; color:${p.fg}\">${p.name[0]}</div>\n      <div class=\"card-body\">\n        <div class=\"card-name\">${p.name}</div>\n        <div class=\"card-info\">${p.rel} · ${monthsShort[p.month - 1]} ${p.day}</div>\n      </div>\n      <div class=\"card-countdown\">\n        <div class=\"card-days${hot ? '' hot'' : ''''}\">${p.daysLeft}</div>\n        <div class=\"card-dlabel\">days</div>\n      </div>\n    `;\n    container.appendChild(card);\n  });\n</script>\n</body>\n</html>"}
INSERT INTO "chat_messages" ("id", "session_id", "role", "content", "intent_type", "catch_payload", "created_at", "execution_time_ms", "input_tokens", "output_tokens", "cost_usd", "run_status", "run_summary", "run_actions", "run_artifacts") VALUES (673, 184, 'user', 'What kind of project is this one', NULL, NULL, '2026-06-11T09:56:38.414Z', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
