INSERT INTO "nexus_messages" ("id", "user_id", "role", "content", "conversation_id", "created_at", "message_type", "project_id", "session_id", "reflection_mode", "idea_mode") VALUES (1882, 1, 'user', 'That is a very, very interesting question. When someone who has no connection to the airline industry, even in evan, if they do when they step into the role as a crew member, it is like learning a foreign language. And often feels like the job itself is the elephant in the room. The intensity is whether or not you will make the cut, whether or not you would make it through training. And then training is all safety focused, and there''s barely any information that you receive prior to actually working. The road to actually really prepare you for that life. And then you find yourself trying to navigate all these new things. And all of it, again is a foreign language, and it takes years to actually get a working system.And it shouldn''t. I personally, literally it created a companion app called compani and with that app, I have a vault, and in that vault, you can upload any relevant documents you need in your AI Companion interprets that information. And assists you, so in the specific for airline crew, you can upload your work rules. You can upload different documents related to the to the job and have a friend in your pocket. That actually interprets it, but that is not the product that we''re discussing the reason why that product I don''t think I don''t think that will work because of the stigma around AI Companion apps like who may or may not take it serious even though it actually works. But if I use that as a basis to making this airline specific pocket app works, then we already have a blueprint of what works there.And just utilize that in this specific use case. And my other app does not address. I mean, it may address the fact that you''re traveling. It does have little stamps that track globally. Everywhere you land and then you can tap on it. And get information about the city. It is not even a feature that is used in that app. Because that''s not what that app is for but if I utilize it in this app and made it airline crew specific, then I think there would be the value proposition right there. So it''s bits and pieces that I have in another app that made me realize that this is something that''s necessary. I''ve already tested it. I''ve asked people, people love the company app. But I have gotten pushback, because they, you know, it felt like a AI boyfriend or girlfriend and that''s not what it is. And I will work on that later. But I feel like a specific tool for this would be and then being able to connect with other crew members, getting feedback from of them, like genuinely, like you''re yelping there, like this restaurant, is the place to go.This food is the place to go.This coffee shop is the place to go.So people are not just stuck in there.Rooms like I do I slam click in order room service.If I otherwise I may go to a spa every now and then.And it''s very rare, but I think, living your life and being able to adapt to that life is important.I struggle with it, and that''s why I think things like this need to exist.And it could even do more than that, I think we can expand the thinking on how it could truly help with the job', '424a6fb2-eca9-4259-9efb-58bbca2a4f49', '2026-06-16T11:56:16.125Z', 'message', 32, NULL, FALSE, FALSE) ON CONFLICT DO NOTHING;
